const reportDate = new Date().toISOString().split('T')[0];
const reports = [
  { id: 'daily-production', name: 'Daily Production Report', department: 'production' },
  { id: 'daily-safety', name: 'Daily Safety Summary', department: 'safety' },
  { id: 'daily-breakdowns', name: 'Breakdown Status Report', department: 'engineering' },
  { id: 'daily-shifts', name: 'Shift Coverage Summary', department: 'control-room' }
];
return { reportDate, reports, scheduledAt: new Date().toISOString() };

const { reports, reportDate } = $json;
const results = reports.map(r => ({
  ...r,
  status: 'queued',
  generatedAt: new Date().toISOString()
}));
return { reportDate, results, total: results.length };

const { results, reportDate } = $json;
return {
  status: 'scheduled',
  reportDate,
  queuedReports: results.length,
  reports: results.map(r => r.name),
  nextRun: 'Tomorrow 06:00 UTC'
};
